// ====================================================================
// 2. FUNCIONES DE BAJO NIVEL (Hardware)
// ====================================================================

void botton_init(){
	//0.abelertsr el reloj de PAy PB, PC
		RCC->AHB2ENR |= (RCC_AHB2ENR_GPIOAEN | RCC_AHB2ENR_GPIOBEN | RCC_AHB2ENR_GPIOCEN);      // Reloj para PA1, PA4 y PA5, PB5, y los de PC

	// 1.Configurar PA1, 5, 4 y PB4 como Entrada con resistencia Pull-Down
	    GPIOA->MODER &= ~((3U << (1 * 2)) | (3U << (4 * 2)) | (3U << (5 * 2))); // Modo Entrada (00) PA
		GPIOA->PUPDR &= ~((3U << (1 * 2)) | (3U << (4 * 2)) | (3U << (5 * 2))); // Limpiar configuración previa
		GPIOA->PUPDR |=  ((2U << (1 * 2)) | (2U << (4 * 2)) | (2U << (5 * 2))); // Activar resistencia Pull-Down (0)

	    GPIOB->MODER &= ~(3U << (5 * 2));         // Modo Entrada (00) para PB4
		GPIOB->PUPDR &= ~(3U << (5 * 2));         // Limpiar configuración previa
		GPIOB->PUPDR |=  (2U << (5 * 2));         // Activar resistencia Pull-Down (0)
	//2. Configuracion PC0 hasta PC9 como entradas PULL-Down
		GPIOC->MODER &= ~(MODER_PC); // Modo Entrada (00) PA
		GPIOC->PUPDR &= ~(MODER_PC); // Limpiar configuración previa
		GPIOC->PUPDR |=  (PUPDR_PC); // Activar resistencia Pull-Down (0)

}
// Función que escanea todos los botones del volante
uint8_t Leer_Botones(void) {

	//--- Los 4 Botones Traseras ---
		if ((GPIOA->IDR & (1 << 1)) != 0) return 1; // PA1 -> Botón 1
		if ((GPIOA->IDR & (1 << 4)) != 0) return 2; // PA4 -> Botón 2
		if ((GPIOA->IDR & (1 << 5)) != 0) return 3; // PA5 -> Botón 3
		if ((GPIOB->IDR & (1 << 5)) != 0) return 4; // PB4 -> Botón 4

    // --- LOS 5 DE LA IZQUIERDA (PC0 a PC4) ---
        if ((GPIOC->IDR & (1 << 0)) != 0) return 5; // PC0
        if ((GPIOC->IDR & (1 << 1)) != 0) return 6; // PC1
        if ((GPIOC->IDR & (1 << 2)) != 0) return 7; // PC2
        if ((GPIOC->IDR & (1 << 3)) != 0) return 8; // PC3
        if ((GPIOC->IDR & (1 << 4)) != 0) return 9; // PC4

    // --- LOS 5 DE LA DERECHA (PC5 a PC9) ---
        if ((GPIOC->IDR & (1 << 5)) != 0) return 10; // PC5
        if ((GPIOC->IDR & (1 << 6)) != 0) return 11; // PC6
        if ((GPIOC->IDR & (1 << 7)) != 0) return 12; // PC7
        if ((GPIOC->IDR & (1 << 8)) != 0) return 13; // PC8
        if ((GPIOC->IDR & (1 << 9)) != 0) return 14; // PC9

    return 0; // Si llega aquí, es que no hay nada pulsado
}

void ILI9488_SendCommand(uint8_t cmd) {
    HAL_GPIO_WritePin(TFT_DC_GPIO_Port, TFT_DC_Pin, GPIO_PIN_RESET); 
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_RESET); 
    HAL_SPI_Transmit(&hspi1, &cmd, 1, 100);
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_SET);   
}

void ILI9488_SendData(uint8_t data) {
    HAL_GPIO_WritePin(TFT_DC_GPIO_Port, TFT_DC_Pin, GPIO_PIN_SET);   
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_RESET); 
    HAL_SPI_Transmit(&hspi1, &data, 1, 100);
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_SET);   
}

void ILI9488_Init(void) {
    HAL_GPIO_WritePin(TFT_RST_GPIO_Port, TFT_RST_Pin, GPIO_PIN_SET);
    HAL_Delay(10);
    HAL_GPIO_WritePin(TFT_RST_GPIO_Port, TFT_RST_Pin, GPIO_PIN_RESET);
    HAL_Delay(10);
    HAL_GPIO_WritePin(TFT_RST_GPIO_Port, TFT_RST_Pin, GPIO_PIN_SET);
    HAL_Delay(120); 

    ILI9488_SendCommand(0xE0); ILI9488_SendData(0x00); ILI9488_SendData(0x03); ILI9488_SendData(0x09); ILI9488_SendData(0x08); ILI9488_SendData(0x16); ILI9488_SendData(0x0A); ILI9488_SendData(0x3F); ILI9488_SendData(0x78); ILI9488_SendData(0x4C); ILI9488_SendData(0x09); ILI9488_SendData(0x0A); ILI9488_SendData(0x08); ILI9488_SendData(0x16); ILI9488_SendData(0x1A); ILI9488_SendData(0x0F);
    ILI9488_SendCommand(0xE1); ILI9488_SendData(0x00); ILI9488_SendData(0x16); ILI9488_SendData(0x19); ILI9488_SendData(0x03); ILI9488_SendData(0x0F); ILI9488_SendData(0x05); ILI9488_SendData(0x32); ILI9488_SendData(0x45); ILI9488_SendData(0x46); ILI9488_SendData(0x04); ILI9488_SendData(0x0E); ILI9488_SendData(0x0D); ILI9488_SendData(0x35); ILI9488_SendData(0x37); ILI9488_SendData(0x0F);

    ILI9488_SendCommand(0xC0); ILI9488_SendData(0x17); ILI9488_SendData(0x15);
    ILI9488_SendCommand(0xC1); ILI9488_SendData(0x41);
    ILI9488_SendCommand(0xC5); ILI9488_SendData(0x00); ILI9488_SendData(0x12); ILI9488_SendData(0x80);

    ILI9488_SendCommand(0x36); ILI9488_SendData(0x28); // Horizontal
    ILI9488_SendCommand(0x3A); ILI9488_SendData(0x66); // 18-bits (RGB666)

    ILI9488_SendCommand(0x11); 
    HAL_Delay(120);            
    ILI9488_SendCommand(0x29); 
}

// ====================================================================
// 3. FUNCIONES DE DIBUJO GEOMÉTRICO Y CARTA DE AJUSTE
// ====================================================================

void ILI9488_FillScreen(uint8_t r, uint8_t g, uint8_t b) {
    ILI9488_SendCommand(0x2A);
    ILI9488_SendData(0); ILI9488_SendData(0);
    ILI9488_SendData(479 >> 8); ILI9488_SendData(479 & 0xFF); 

    ILI9488_SendCommand(0x2B);
    ILI9488_SendData(0); ILI9488_SendData(0);
    ILI9488_SendData(319 >> 8); ILI9488_SendData(319 & 0xFF); 

    ILI9488_SendCommand(0x2C); 

    HAL_GPIO_WritePin(TFT_DC_GPIO_Port, TFT_DC_Pin, GPIO_PIN_SET);
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_RESET);

    for(uint32_t i = 0; i < 153600; i++) {
        HAL_SPI_Transmit(&hspi1, &r, 1, 10);
        HAL_SPI_Transmit(&hspi1, &g, 1, 10);
        HAL_SPI_Transmit(&hspi1, &b, 1, 10);
    }
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_SET);
}

void ILI9488_FillRect(uint16_t x, uint16_t y, uint16_t width, uint16_t height, uint8_t r, uint8_t g, uint8_t b) {
    uint16_t x2 = x + width - 1;
    uint16_t y2 = y + height - 1;

    ILI9488_SendCommand(0x2A); 
    ILI9488_SendData(x >> 8); ILI9488_SendData(x & 0xFF);
    ILI9488_SendData(x2 >> 8); ILI9488_SendData(x2 & 0xFF);

    ILI9488_SendCommand(0x2B); 
    ILI9488_SendData(y >> 8); ILI9488_SendData(y & 0xFF);
    ILI9488_SendData(y2 >> 8); ILI9488_SendData(y2 & 0xFF);

    ILI9488_SendCommand(0x2C);

    HAL_GPIO_WritePin(TFT_DC_GPIO_Port, TFT_DC_Pin, GPIO_PIN_SET);
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_RESET);

    uint32_t total_pixels = width * height;
    for(uint32_t i = 0; i < total_pixels; i++) {
        HAL_SPI_Transmit(&hspi1, &r, 1, 10);
        HAL_SPI_Transmit(&hspi1, &g, 1, 10);
        HAL_SPI_Transmit(&hspi1, &b, 1, 10);
    }
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_SET);
}

void ILI9488_DrawImage(uint16_t x, uint16_t y, uint16_t width, uint16_t height, const uint16_t* image_array) {
    uint16_t x2 = x + width - 1;
    uint16_t y2 = y + height - 1;

    ILI9488_SendCommand(0x2A);
    ILI9488_SendData(x >> 8); ILI9488_SendData(x & 0xFF);
    ILI9488_SendData(x2 >> 8); ILI9488_SendData(x2 & 0xFF);

    ILI9488_SendCommand(0x2B);
    ILI9488_SendData(y >> 8); ILI9488_SendData(y & 0xFF);
    ILI9488_SendData(y2 >> 8); ILI9488_SendData(y2 & 0xFF);

    ILI9488_SendCommand(0x2C);

    HAL_GPIO_WritePin(TFT_DC_GPIO_Port, TFT_DC_Pin, GPIO_PIN_SET);
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_RESET);

    uint32_t total_pixels = width * height;
    for(uint32_t i = 0; i < total_pixels; i++) {
        uint16_t color565 = image_array[i];
        uint8_t r = (color565 & 0xF800) >> 8;
        uint8_t g = (color565 & 0x07E0) >> 3;
        uint8_t b = (color565 & 0x001F) << 3;
        HAL_SPI_Transmit(&hspi1, &r, 1, 10);
        HAL_SPI_Transmit(&hspi1, &g, 1, 10);
        HAL_SPI_Transmit(&hspi1, &b, 1, 10);
    }
    HAL_GPIO_WritePin(TFT_CS_GPIO_Port, TFT_CS_Pin, GPIO_PIN_SET);
}

void ILI9488_DrawColorBars(void) {
    uint16_t ancho_barra = 80;
    uint16_t alto_pantalla = 480;

    ILI9488_FillRect(0, 0, ancho_barra, alto_pantalla, 255, 0, 0);
    ILI9488_FillRect(80, 0, ancho_barra, alto_pantalla, 0, 255, 0);
    ILI9488_FillRect(160, 0, ancho_barra, alto_pantalla, 0, 0, 255);
    ILI9488_FillRect(240, 0, ancho_barra, alto_pantalla, 255, 255, 255);
}

// ====================================================================
// 4. MOTOR DE TEXTO
// ====================================================================

void ILI9488_DrawChar(uint16_t x, uint16_t y, char c, uint8_t r, uint8_t g, uint8_t b, uint8_t bg_r, uint8_t bg_g, uint8_t bg_b, uint8_t size) {
    if (c >= 'a' && c <= 'z') { c = c - 32; }
    if ((c < 32) || (c > 90)) return; 

    uint16_t font_index = (c - 32) * 5;

    for (int8_t i = 0; i < 5; i++) { 
        uint8_t line = Font5x7[font_index + i];
        for (int8_t j = 0; j < 8; j++) { 
            if (line & 0x1) {
                ILI9488_FillRect(x + (i * size), y + (j * size), size, size, r, g, b);
            } else if (bg_r != 255 || bg_g != 255 || bg_b != 255) {
                ILI9488_FillRect(x + (i * size), y + (j * size), size, size, bg_r, bg_g, bg_b);
            }
            line >>= 1;
        }
    }
}

void ILI9488_DrawString(uint16_t x, uint16_t y, char *str, uint8_t r, uint8_t g, uint8_t b, uint8_t bg_r, uint8_t bg_g, uint8_t bg_b, uint8_t size) {
    while (*str) {
        ILI9488_DrawChar(x, y, *str, r, g, b, bg_r, bg_g, bg_b, size);
        x += 6 * size; 
        str++;
    }
}
