void Helios_DrawDashboard_Static(int Pres_reuda) {
    ILI9488_FillScreen(0, 0, 0); 

    // --- ZONA SUPERIOR (Cabecera y Datos Core) ---
    ILI9488_FillRect(0, 0, 480, 40, 0, 50, 255);
    ILI9488_DrawString(100, 8, "HELIOS", 255, 255, 0, 0, 50, 255, 4);
    ILI9488_DrawString(250, 8, "RACE", 255, 255, 0, 0, 50, 255, 4);
    ILI9488_DrawString(400, 15, "IESC", 0, 255, 0, 0, 50, 255, 3);

    ILI9488_DrawString(165, 80, "SPEED KPH", 255, 255, 255, 0, 0, 0, 2);
    ILI9488_DrawString(30, 120, "MODE", 255, 255, 255, 0, 0, 0, 2);
    ILI9488_DrawString(340, 120, "BATERIA", 255, 255, 255, 0, 0, 0, 2);

    // --- ZONA INFERIOR (Grid de 6 parámetros) ---
    // Líneas del Grid (Color gris oscuro)
    ILI9488_FillRect(0, 200, 480, 2, 50, 50, 50);   // Horizontal superior
    ILI9488_FillRect(0, 260, 480, 2, 50, 50, 50);   // Horizontal media
    ILI9488_FillRect(155, 200, 2, 120, 50, 50, 50); // Vertical 1
    ILI9488_FillRect(315, 200, 2, 120, 50, 50, 50); // Vertical 2

    // Etiquetas estáticas (Color gris claro para no distraer)
    // Fila 1
    ILI9488_DrawString(10, 220, "RPM:", 180, 180, 180, 0, 0, 0, 2);
    ILI9488_DrawString(165, 220, "TMP:", 180, 180, 180, 0, 0, 0, 2);
    if(Pres_reuda == 2){
    ILI9488_DrawString(325, 220, "PRS2:", 180, 180, 180, 0, 0, 0, 2);}
    else if (Pres_reuda == 3){
    ILI9488_DrawString(325, 220, "PRS3:", 180, 180, 180, 0, 0, 0, 2);
    }
    else { ILI9488_DrawString(325, 220, "PRS1:", 180, 180, 180, 0, 0, 0, 2);
    }
    // Fila 2
    ILI9488_DrawString(10, 280, "VOL:", 180, 180, 180, 0, 0, 0, 2);
    ILI9488_DrawString(165, 280, "AMP:", 180, 180, 180, 0, 0, 0, 2);
    ILI9488_DrawString(325, 280, "ETA:", 180, 180, 180, 0, 0, 0, 2);
}

void Helios_UpdateTelemetry(int speed, int battery_percent, uint8_t is_eco_mode,
                            int temp, int pre, int rpm, float volt, float amp,
                            int eta_h, int eta_m, uint8_t force_redraw ) {

    // MEMORIA DEL SISTEMA: Variables estáticas para recordar qué dibujamos la última vez
    static int last_speed = -1;
    static int last_battery = -1;
    static uint8_t last_mode = 255;
    static int last_temp = -1;
    static int last_pre = -1;
    static int last_rpm = -1;
    static float last_volt = -1.0;
    static float last_amp = -1.0;
    static int last_eta_h = -1;
    static int last_eta_m = -1;

    if (force_redraw == 1) {
            last_speed = -1;
            last_battery = -1;
            last_mode = 255;
            last_temp = -1;
            last_pre = -1;
            last_rpm = -1;
            last_volt = -1.0;
            last_amp = -1.0;
            last_eta_h = -1;
            last_eta_m = -1;
        }

    char str_buffer[15];
    uint8_t r, g, b;

    // 1. VELOCIDAD (Solo dibuja si la velocidad ha cambiado)
    if (speed != last_speed) {
        sprintf(str_buffer, "%02d", speed);
        ILI9488_DrawString(160, 120, str_buffer, 255, 255, 255, 0, 0, 0, 10);
        last_speed = speed;
    }

    // 2. MODO (ECO/RACE)
    if (is_eco_mode != last_mode) {
        // Nota: "ECO " tiene un espacio extra para borrar la 'E' de RACE si cambiamos
        if (is_eco_mode) { ILI9488_DrawString(30, 160, "ECO ", 0, 255, 0, 0, 0, 0, 3); }
        else { ILI9488_DrawString(30, 160, "RACE", 255, 0, 0, 0, 0, 0, 3); }
        last_mode = is_eco_mode;
    }

    // 3. BATERÍA (Porcentaje + Barra)
    if (battery_percent != last_battery) {
        if (battery_percent > 50) { r = 0; g = 255; b = 0; }
        else if (battery_percent > 15) { r = 255; g = 255; b = 0; }
        else { r = 255; g = 0; b = 0; }

        sprintf(str_buffer, "%02d%%", battery_percent);
        ILI9488_DrawString(340, 160, str_buffer, r, g, b, 0, 0, 0, 4);

        ILI9488_FillRect(340, 190, battery_percent, 8, r, g, b);
        ILI9488_FillRect(340 + battery_percent, 190, 100 - battery_percent, 8, 50, 50, 50);

        last_battery = battery_percent;
    }

    // 4. RPM
    if (rpm != last_rpm) {
        sprintf(str_buffer, "%04d", rpm);
        ILI9488_DrawString(65, 220, str_buffer, 255, 255, 255, 0, 0, 0, 2);
        last_rpm = rpm;
    }

    // 5. TEMPERATURA (¡Alerta! Si pasa de 75, forzamos el redibujado para que parpadee)
    if (temp != last_temp || temp > 75) {
        static uint8_t parpadeo = 0;
        if (temp > 65) parpadeo = !parpadeo; else parpadeo = 0; // Alterna 0 y 1 en emergencia

        uint8_t bg_r = (temp > 65 && parpadeo == 1) ? 255 : 0;

        sprintf(str_buffer, "%02d C", temp);
        ILI9488_DrawString(220, 220, str_buffer, 255, 255, 255, bg_r, 0, 0, 2);
        last_temp = temp;
    }

    // 6. PRESIÓN
    if (pre != last_pre) {
        sprintf(str_buffer, "%d BAR", pre);
        ILI9488_DrawString(380, 220, str_buffer, 0, 255, 255, 0, 0, 0, 2);
        last_pre = pre;
    }


    // 7. VOLTAJE
    if (volt != last_volt) {
        int v_int = (int)volt; int v_dec = (int)((volt - v_int) * 10);
        sprintf(str_buffer, "%02d.%dV", v_int, v_dec);
        ILI9488_DrawString(65, 280, str_buffer, 255, 255, 0, 0, 0, 0, 2);
        last_volt = volt;
    }

    // 8. AMPERIOS
    if (amp != last_amp) {
        int a_int = (int)amp; int a_dec = (int)((amp - a_int) * 10);
        sprintf(str_buffer, "%02d.%dA", a_int, a_dec);
        ILI9488_DrawString(220, 280, str_buffer, 255, 150, 0, 0, 0, 0, 2);
        last_amp = amp;
    }

    // 9. TIEMPO ESTIMADO (ETA)
    if (eta_h != last_eta_h || eta_m != last_eta_m) {
        sprintf(str_buffer, "%dh%02dm", eta_h, eta_m);
        ILI9488_DrawString(380, 280, str_buffer, 0, 255, 0, 0, 0, 0, 2);
        last_eta_h = eta_h;
        last_eta_m = eta_m;
    }
}
